// Import required modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const NotificationLog = require('./models/NotificationLog');
const Task = require('./models/Task');
const { sendNotification } = require('./services/notificationService');

/**
 * Scheduling Engine to handle task notifications
 * It runs tasks based on defined schedules and handles multiple scenarios including catch-up logic.
 */

// Utility function to get current time in UTC+7
const getCurrentTimeInUTCPlus7 = () => {
  return new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Bangkok' }));
};

/**
 * Start the scheduling engine
 */
const startSchedulingEngine = () => {
  // Schedule tasks based on their recurrence
  cron.schedule('* * * * *', async () => {
    try {
      const tasks = await Task.find({ 'status': 'active' });
      const now = getCurrentTimeInUTCPlus7();

      tasks.forEach(async (task) => {
        const taskTime = new Date(now);
        const taskHours = parseInt(task.recurrence.time.split(':')[0]);
        const taskMinutes = parseInt(task.recurrence.time.split(':')[1]);

        // Check if task time now
d        if ((now.getHours() === taskHours) && (now.getMinutes() === taskMinutes)) {
          // Handle the available user
          const availableUser = getAvailableAssignee(task);

          if (availableUser) {
            await sendNotification(availableUser, task);
            await logNotification(task.id, 'success');
          } else {
            console.log(`No available assignee for task ${task.id}`);
          }
        }
      });
    } catch (error) {
      console.error('Error scheduling tasks:', error);
    }
  });
};

/**
 * Get the next available assignee from the task's assignees list
 * @param {Object} task - The task object.
 * @returns {string|null} - The ID of the available user or null if none found.
 */
const getAvailableAssignee = (task) => {
  const { assignees, rotationIndex, unavailableMembers } = task;
  for (let i = 0; i < assignees.length; i++) {
    const index = (rotationIndex + i) % assignees.length;
    const assigneeId = assignees[index];

    if (!unavailableMembers.includes(assigneeId)) {
      return assigneeId;
    }
  }
  return null;
};

/**
 * Log the notification
 * @param {string} taskId - The task ID.
 * @param {string} status - Status of the notification.
 */
const logNotification = async (taskId, status) => {
  await NotificationLog.create({
    taskId: taskId,
    sentAt: new Date(),
    status: status,
  });
};

// Export the start function
module.exports = {
  startSchedulingEngine,
};
